```class Solution {
public:
    int hardestWorker(int n, vector<vector<int>>& logs) {
        sort(logs.begin(), logs.end(), [](const vector<int>& a, const vector<int>& b) {
            return a[1] < b[1];
        });
        int result = logs[0][1];
        for (int i = 1; i < n; i++) {
            if (logs[i][1] > result) {
                result = logs[i][1];
            }
        }
        return result;
    }
};
